    pass


class Account:
    PREMIUM = "premium"
    STANDARD = "standard"

    TRANSFER_LIMITS = {
        PREMIUM: Decimal("10000.00"),
        STANDARD: Decimal("2500.00"),
    }

    def __init__(self, account_id: str, tier: str):
        if tier not in (self.PREMIUM, self.STANDARD):
            raise ValueError(f"Unknown tier: {tier}")
        self.account_id = account_id
        self.tier = tier

    @property
    def transfer_limit(self) -> Decimal:
        return self.TRANSFER_LIMITS[self.tier]

    @property
    def is_premium(self) -> bool:
        return self.tier == self.PREMIUM


class TransferRequest:
    VALID_FREQUENCIES = {"daily", "weekly", "biweekly", "monthly"}

    def __init__(self, amount: Decimal, frequency: str, destination_account_id: str):
        self.amount = Decimal(str(amount))
        self.frequency = frequency
        self.destination_account_id = destination_account_id


