    if request.amount <= Decimal("0"):
        raise InvalidTransferError("Transfer amount must be greater than zero.")

    if request.frequency not in TransferRequest.VALID_FREQUENCIES:
        raise InvalidTransferError(f"Invalid frequency: {request.frequency}")

    if not request.destination_account_id:
        raise InvalidTransferError("Destination account ID is required.")

    if request.amount > account.transfer_limit:
        raise TransferLimitExceededError(
            f"Amount {request.amount} exceeds the {account.tier} tier limit of "
            f"{account.transfer_limit}."
        )

    return {
        "status": "scheduled",
        "account_id": account.account_id,
        "tier": account.tier,
        "amount": request.amount,
        "frequency": request.frequency,
        "destination": request.destination_account_id,
    }


