class TestConfirmationPayload:

    def test_confirmation_contains_scheduled_status(self, premium_account, make_request):
        result = schedule_recurring_transfer(premium_account, make_request(100))
        assert result["status"] == "scheduled"

    def test_confirmation_contains_correct_account_id(self, premium_account, make_request):
        result = schedule_recurring_transfer(premium_account, make_request(100))
        assert result["account_id"] == premium_account.account_id

