    (Account.PREMIUM,  Decimal("2500.00"),  True),
    (Account.PREMIUM,  Decimal("9999.99"),  True),
    (Account.PREMIUM,  Decimal("10000.00"), True),  # at cap
    (Account.PREMIUM,  Decimal("10000.01"), False), # 1 cent over cap
    (Account.PREMIUM,  Decimal("99999.00"), False),
])
def test_boundary_values(tier, amount, should_succeed):
